# Managing collection lifecycle: creation, recreation, deletion
from qdrant_client.models import (
    VectorParams, Distance, QuantizationConfig,
    ScalarQuantizationConfig, ScalarType,
    OptimizersConfigDiff,
)

COLLECTION = 'agent_memories'
DIM        = 1024  # voyage-3

def ensure_collection(qdrant, name: str, dim: int) -> None:
    existing = {c.name for c in qdrant.get_collections().collections}
    if name in existing:
        return  # already exists, skip
    qdrant.create_collection(
        name,
        vectors_config=VectorParams(size=dim, distance=Distance.COSINE),
        quantization_config=QuantizationConfig(
            scalar=ScalarQuantizationConfig(
                type=ScalarType.INT8,
                quantile=0.99,
                always_ram=True,
            )
        ),
        # Tune optimizer: delay indexing until 50k vectors are buffered
        optimizers_config=OptimizersConfigDiff(
            indexing_threshold=50_000,
        ),
    )
    # Create payload indexes immediately so filters work from the start
    from qdrant_client.models import PayloadSchemaType
    for field, schema in [
        ('user_id',      PayloadSchemaType.KEYWORD),
        ('content_hash', PayloadSchemaType.KEYWORD),
        ('indexed_at',   PayloadSchemaType.FLOAT),
    ]:
        qdrant.create_payload_index(name, field, schema)

def recreate_collection(qdrant, name: str, dim: int) -> None:
    # Called when switching embedding models (dimension change)
    try:
        qdrant.delete_collection(name)
    except Exception:
        pass  # collection did not exist
    ensure_collection(qdrant, name, dim)

ensure_collection(qdrant, COLLECTION, DIM)

# Delete stale embeddings by metadata filter
# Use case: remove all memories for a deleted user, or expire old documents
import time
from qdrant_client.models import Filter, FieldCondition, MatchValue, Range

def delete_user_memories(qdrant, collection: str, user_id: str) -> int:
    result = qdrant.delete(
        collection,
        points_selector=Filter(must=[
            FieldCondition(key='user_id', match=MatchValue(value=user_id))
        ]),
    )
    return result.status.value  # 'completed'

def delete_old_memories(qdrant, collection: str, max_age_seconds: float) -> None:
    cutoff = time.time() - max_age_seconds
    qdrant.delete(
        collection,
        points_selector=Filter(must=[
            FieldCondition(
                key='indexed_at',
                range=Range(lt=cutoff),
            )
        ]),
    )

# Count before deleting for audit logs
def count_user_memories(qdrant, collection: str, user_id: str) -> int:
    return qdrant.count(
        collection,
        count_filter=Filter(must=[
            FieldCondition(key='user_id', match=MatchValue(value=user_id))
        ]),
    ).count

# Expire all memories older than 30 days
delete_old_memories(qdrant, 'memories', max_age_seconds=30 * 86400)
